"""Tests for the CI workflow generator.

Run with `mise run ci:test-generator` (which executes from the scripts/ dir) or
directly via `python -m unittest test_generate_ci_workflow` from scripts/.

The headline test (`test_step_conditions_preserve_original_behavior`) proves that
each generated allow-list runs on exactly the variants the original hand-written
conditions selected, so regenerating preserves CI behavior.
"""

import json
import os
import re
import sys
import tempfile
import unittest
from pathlib import Path

sys.path.insert(0, os.path.dirname(os.path.abspath(__file__)))

import generate_ci_workflow as gen  # noqa: E402

ALL_ENVS = [
    "linux-arm64-egl",
    "linux-arm64-vulkan",
    "linux-x64-egl",
    "linux-x64-vulkan",
    "macos-arm64-metal",
    "macos-arm64-vulkan",
    "macos-arm64-egl",
    "ios-arm64-metal",
    "ios-simulator-arm64-metal",
    "windows-x64-vulkan",
    "windows-x64-wgl",
]


# Original hand-written conditions from ci.yml, encoded as predicates. Each maps
# a variant to whether the step ran under the pre-generator workflow.
def _not_macos_egl_non_ios(env: str) -> bool:
    return env != "macos-arm64-egl" and not env.startswith("ios-")


ORIGINAL_CONDITIONS = {
    "configure": lambda env: True,
    "build": lambda env: env.startswith("ios-"),
    "test": lambda env: not env.startswith("ios-"),
    "//bindings/java-ffm:build": _not_macos_egl_non_ios,
    "//bindings/java-jni:build": _not_macos_egl_non_ios,
    "//bindings/dotnet:test": _not_macos_egl_non_ios,
    "//bindings/kotlin-native:build": lambda env: (
        _not_macos_egl_non_ios(env)
        and not env.startswith("windows-")
        and not env.startswith("linux-arm64-")
    ),
    "//bindings/rust:ci": _not_macos_egl_non_ios,
    "//bindings/swift:test": lambda env: (
        env != "macos-arm64-egl" and env.startswith("macos-")
    ),
    "//bindings/zig:ci": lambda env: not env.startswith("ios-"),
    "//examples/lwjgl-map:build": lambda env: "vulkan" in env,
    "//examples/rust-map:ci": _not_macos_egl_non_ios,
    "//examples/swift-map:build": lambda env: env == "macos-arm64-metal",
    "//examples/zig-map:build": _not_macos_egl_non_ios,
    "//examples/zig-readback:run": lambda env: not env.startswith("ios-"),
}


def _load() -> tuple[dict, list[str], str]:
    manifest = gen.load_manifest()
    configs = gen.discover_variant_configs()
    all_envs = gen.validate(manifest, configs)
    return manifest, all_envs, gen.render(manifest, all_envs)


class ManifestTests(unittest.TestCase):
    def test_variant_configs_match_runners(self) -> None:
        """Every CI target must be backed by a mise config, and vice versa."""
        manifest = gen.load_manifest()
        configs = gen.discover_variant_configs()
        self.assertEqual(set(manifest["runners"]), set(configs))

    def test_runners_are_canonical_order(self) -> None:
        manifest = gen.load_manifest()
        self.assertEqual(list(manifest["runners"].keys()), ALL_ENVS)

    def test_validate_accepts_real_manifest(self) -> None:
        manifest = gen.load_manifest()
        configs = gen.discover_variant_configs()
        self.assertEqual(gen.validate(manifest, configs), ALL_ENVS)


class ResolveTests(unittest.TestCase):
    def test_all_expands_to_canonical_order(self) -> None:
        self.assertEqual(
            gen.resolve_envs({"envs": "all"}, ALL_ENVS), ALL_ENVS
        )

    def test_explicit_list_canonicalized(self) -> None:
        step = {"envs": ["windows-x64-wgl", "ios-arm64-metal", "linux-x64-egl"]}
        self.assertEqual(
            gen.resolve_envs(step, ALL_ENVS),
            ["linux-x64-egl", "ios-arm64-metal", "windows-x64-wgl"],
        )


class ValidationFailureTests(unittest.TestCase):
    def _validate(self, manifest: dict, configs: list[str]) -> None:
        gen.validate(manifest, configs)

    def test_runner_without_config_is_rejected(self) -> None:
        manifest = {"runners": {"linux-x64-egl": "ubuntu-latest"}, "steps": []}
        with self.assertRaisesRegex(gen.ManifestError, "without a .mise"):
            self._validate(manifest, configs=["linux-x64-vulkan"])

    def test_config_without_runner_is_rejected(self) -> None:
        manifest = {"runners": {"linux-x64-egl": "ubuntu-latest"}, "steps": []}
        with self.assertRaisesRegex(gen.ManifestError, "without an entry"):
            self._validate(
                manifest, configs=["linux-x64-egl", "linux-x64-vulkan"]
            )

    def test_unknown_env_in_step_is_rejected(self) -> None:
        manifest = {
            "runners": {"linux-x64-egl": "ubuntu-latest"},
            "steps": [{"task": "configure", "envs": ["linux-x64-vulkan"]}],
        }
        with self.assertRaisesRegex(gen.ManifestError, "unknown variants"):
            self._validate(manifest, configs=["linux-x64-egl"])

    def test_duplicate_task_is_rejected(self) -> None:
        manifest = {
            "runners": {"linux-x64-egl": "ubuntu-latest"},
            "steps": [
                {"task": "build", "envs": ["linux-x64-egl"]},
                {"task": "build", "envs": ["linux-x64-egl"]},
            ],
        }
        with self.assertRaisesRegex(gen.ManifestError, "reuses task"):
            self._validate(manifest, configs=["linux-x64-egl"])

    def test_empty_envs_is_rejected(self) -> None:
        manifest = {
            "runners": {"linux-x64-egl": "ubuntu-latest"},
            "steps": [{"task": "build", "envs": []}],
        }
        with self.assertRaisesRegex(gen.ManifestError, "no variants"):
            self._validate(manifest, configs=["linux-x64-egl"])

    def test_missing_task_and_envs_are_rejected(self) -> None:
        configs = ["linux-x64-egl"]
        with self.assertRaisesRegex(gen.ManifestError, "missing a 'task'"):
            gen.validate(
                {"runners": {"linux-x64-egl": "u"}, "steps": [{}]}, configs
            )
        with self.assertRaisesRegex(gen.ManifestError, "missing 'envs'"):
            gen.validate(
                {"runners": {"linux-x64-egl": "u"}, "steps": [{"task": "x"}]},
                configs,
            )


class RenderTests(unittest.TestCase):
    def test_render_is_valid_yaml(self) -> None:
        import yaml

        _, _, text = _load()
        parsed = yaml.safe_load(text)
        self.assertEqual(
            list(parsed["jobs"]), ["hygiene", "docs", "variants", "required"]
        )

    def test_render_is_deterministic(self) -> None:
        manifest, all_envs, _ = _load()
        self.assertEqual(
            gen.render(manifest, all_envs), gen.render(manifest, all_envs)
        )

    def test_generated_header_present(self) -> None:
        _, _, text = _load()
        self.assertTrue(text.startswith("# This file is generated"))
        self.assertIn("mise run ci:generate-workflow", text)

    def test_matrix_runners_match_manifest(self) -> None:
        import yaml

        manifest, _, text = _load()
        parsed = yaml.safe_load(text)
        include = parsed["jobs"]["variants"]["strategy"]["matrix"]["include"]
        self.assertEqual(
            {item["mise_env"]: item["runner"] for item in include},
            manifest["runners"],
        )

    def test_unnamed_all_envs_step_has_no_condition(self) -> None:
        import yaml

        _, _, text = _load()
        steps = yaml.safe_load(text)["jobs"]["variants"]["steps"]
        configure = next(s for s in steps if s.get("run") == "mise run configure")
        self.assertNotIn("if", configure)
        self.assertNotIn("name", configure)

    def test_reason_rendered_as_comments(self) -> None:
        _, _, text = _load()
        self.assertIn(
            "      # linux-arm64: no Kotlin/Native host", text
        )

    def test_step_conditions_preserve_original_behavior(self) -> None:
        """Each generated allow-list equals the original condition's set."""
        import yaml

        manifest = gen.load_manifest()
        configs = gen.discover_variant_configs()
        all_envs = gen.validate(manifest, configs)
        steps = yaml.safe_load(gen.render(manifest, all_envs))["jobs"][
            "variants"
        ]["steps"]

        generated: dict[str, set[str]] = {}
        for step in steps:
            if "run" not in step:
                continue
            task = step["run"].removeprefix("mise run ")
            condition = step.get("if")
            if condition is None:
                generated[task] = set(all_envs)
            else:
                match = re.search(r"fromJson\('(\[.*?\])'\)", condition)
                self.assertIsNotNone(match, f"unparseable if: {condition}")
                generated[task] = set(json.loads(match.group(1)))

        self.assertEqual(
            set(generated), set(ORIGINAL_CONDITIONS),
            "generator task set diverged from the original conditions",
        )
        for task, predicate in ORIGINAL_CONDITIONS.items():
            expected = {env for env in all_envs if predicate(env)}
            self.assertEqual(
                generated[task],
                expected,
                f"behavior changed for {task!r}",
            )


class GenerateTests(unittest.TestCase):
    def test_generate_round_trips_committed_workflow(self) -> None:
        """Regenerating must reproduce the checked-in workflow byte-for-byte."""
        with tempfile.TemporaryDirectory() as tmp:
            out = Path(tmp) / "ci.yml"
            text = gen.generate(workflow_path=out)
            committed = gen.WORKFLOW_PATH.read_text(encoding="utf-8")
            self.assertEqual(text, committed)


if __name__ == "__main__":
    unittest.main()

